const b = $input.all()[0].json;
const SERIES = { veiculo_novo: 20714, veiculo_usado: 20715, imovel: 433, pessoal: 20586, consignado: 20585 };
const LABELS  = { veiculo_novo: 'Veículo novo (PF)', veiculo_usado: 'Veículo usado (PF)', imovel: 'Crédito imobiliário', pessoal: 'Crédito pessoal', consignado: 'Consignado' };

const taxa   = parseFloat(b.taxa);
const tipo   = b.tipo || 'pessoal';
const leadId = b.lead_id || null;
const serie  = SERIES[tipo];

if (!taxa || isNaN(taxa)) throw new Error('taxa inválida ou ausente');
if (!serie)               throw new Error('tipo inválido: ' + tipo);

return [{ json: { taxa, tipo, leadId, serie, label: LABELS[tipo] || tipo } }];

const bacen  = $input.all()[0].json;
const taxa   = $('Validar Dados').item.json.taxa;
const tipo   = $('Validar Dados').item.json.tipo;
const leadId = $('Validar Dados').item.json.leadId;
const label  = $('Validar Dados').item.json.label;

const media  = parseFloat(Array.isArray(bacen) ? bacen[0].valor : bacen.valor);
const desvio = +( ((taxa - media) / media) * 100 ).toFixed(1);

let laudo, cor;
if      (desvio > 50)  { laudo = 'ABUSIVO';        cor = 'red';   }
else if (desvio >= 20) { laudo = 'NO LIMITE';       cor = 'amber'; }
else                   { laudo = 'DENTRO DA MÉDIA'; cor = 'green'; }

const dataRef = Array.isArray(bacen) ? bacen[0].data : bacen.data;

// Calcula excesso estimado (Price simplificado — referência)
const excesso = desvio > 0 ? +(taxa * (desvio / 100)).toFixed(3) : 0;

return [{ json: {
  taxa, media_bacen: media, desvio, laudo, cor,
  tipo, label, data_ref: dataRef,
  excesso_mensal_pct: excesso,
  leadId
}}];
